import{c as n}from"./LoadingScreen-B5VR7K9u.js";import{f as r,g as y,w as l,a as o,y as x,b as N,T as c,s as k,m as t,t as v,p as s,E as m}from"./vendor-CKqqAmYr.js";import{_ as I}from"./index-OaA0B_dp.js";const u={round1:{startNode:"r1_start",r1_start:{nodeId:"r1_start",speaker:"pharma",speakerName:"诺华制药代表",text:"Spinraza是目前全球唯一获批的SMA治疗药物。我们很清楚中国患者的需求——我们收到过很多中国家庭的来信，也见过那些孩子的照片。但研发的现实是：这个药从基础研究走到今天用了整整18年，投入超过20亿美元。我们的初始报价是每支12万元。我知道这个数字听起来很高，但请理解——当全球只有6万名患者时，每一支药背后分摊的研发成本是一个天文数字。",emotion:"confident",options:[{id:"A",type:"pressure",label:"价格质疑",text:"12万元一支？你们在澳大利亚的定价折合人民币还不到6万。为什么中国患者要付双倍的价钱？请解释这个差距。",nextNode:"r1_pressure_response",effects:{priceChange:-15e3}},{id:"B",type:"empathy",label:"患者优先",text:"我桌上放着全国1200名SMA患儿的名单，最小的只有8个月大。如果不能尽快纳入医保，这些孩子中的大多数等不到明年。今天我不是来砍价的——我是来处理一场公共卫生危机。",nextNode:"r1_empathy_response",effects:{priceChange:-8e3}},{id:"C",type:"technical",label:"价值分析",text:'根据国际通用的"性价比"测算模型，这个药每帮患者延长一年高质量生命，合理花费应该在5-7万元。12万远超这个范围——请贵方提供你们自己的测算依据。',nextNode:"r1_technical_response",effects:{priceChange:-12e3}}]},r1_pressure_response:{nodeId:"r1_pressure_response",speaker:"pharma",speakerName:"诺华制药代表",text:"（略显不悦，但控制住了情绪）各国的定价受市场规模、物流成本等多种因素影响，不能简单比较。澳大利亚有政府专项罕见病基金补贴，而中国市场需要我们自己承担全部商业风险。（停顿）但我理解你的立场。请给我们内部讨论的时间，第二轮我们会拿出更有诚意的方案。",emotion:"defensive",isEndOfRound:!0},r1_empathy_response:{nodeId:"r1_empathy_response",speaker:"pharma",speakerName:"诺华制药代表",text:"（沉默了好一会儿，声音变轻了）8个月大……这个数字让我很难受。以患者为中心是我们做这个药的初衷——不是为了利润，是因为我们见过那些孩子的眼睛。（整理了一下情绪）请给我们一些时间，第二轮我们会认真考虑一个更可及的价格方案。",emotion:"sympathetic",isEndOfRound:!0},r1_technical_response:{nodeId:"r1_technical_response",speaker:"pharma",speakerName:"诺华制药代表",text:'（认真翻阅资料）贵方的测算框架很专业，但有一个盲点：Spinraza的研发周期长达18年，其中前12年都是在试错——那些失败的项目成本，在"性价比"模型里是算不进去的。不过——（合上文件，语气诚恳）我承认12万的报价确实有调整空间。第二轮我们拿出诚意。',emotion:"defensive",isEndOfRound:!0}},round2:{startNode:"r2_start",r2_start:{nodeId:"r2_start",speaker:"pharma",speakerName:"诺华制药代表",text:"（神情比上一轮更加严肃）我跟总部通了紧急电话。经过讨论，我们决定将价格调整至每支8万元。这是我们基于中国市场的特殊情况能做出的最大诚意了。坦率地说，再往下降，每一支药都将在亏损——全球没有任何一个市场有这个先例。",emotion:"conciliatory",options:[{id:"A",type:"pressure",label:"坚守底线（高风险）",text:"8万还是太高。如果贵方不能降至6万以内，我只能遗憾地终止今天的谈判。这不是威胁——1200个家庭在等我的结果，我没有退路。",nextNode:"r2_pressure_response",effects:{priceChange:-28e3}},{id:"B",type:"empathy",label:"寻求合作（稳妥）",text:'我接到了一位SMA患儿母亲的电话。她的孩子3岁了还不能独坐。她说："谈判官，我们不是要免费，只是想要一个希望。"如果贵方今天能把价格降到患者真正可及的程度——我愿意在后续推动建立患者援助计划，让这个药不是进了目录就完事，而是真正用到每个需要的孩子身上。',nextNode:"r2_empathy_response",effects:{priceChange:-25e3}}]},r2_pressure_response:{nodeId:"r2_pressure_response",speaker:"pharma",speakerName:"诺华制药代表",text:"（脸色变了，与团队成员用英语低声争论了近一分钟。气氛极度紧张。）……这是我从业二十年来最艰难的谈判。6万以内——（深吸一口气）这个要求在全球任何董事会都会被直接否决。但如果我今天说不，那些孩子就真的没有机会了。好。我向总部承担这个决定的风险。这是我们的最终报价。",emotion:"defensive",triggerEnvelope:!0},r2_empathy_response:{nodeId:"r2_empathy_response",speaker:"pharma",speakerName:"诺华制药代表",text:"（眼眶微微发红，声音有些沙哑）那个电话……让我想起我们研发团队里的一位科学家。她花了整整15年做这个药，她办公桌上一直放着一张SMA患儿的照片。（停顿了很久）你说得对，进了目录不是终点。患者援助计划这个提议很有价值——我们愿意为了这些孩子，做出超出常规的让步。这是最终报价。",emotion:"sympathetic",triggerEnvelope:!0}}},_={round1:{startNode:"r1_start",r1_start:{nodeId:"r1_start",speaker:"pharma",speakerName:"全球肿瘤药事业部代表",text:"艾瑞卡在欧美市场的定价折合人民币约15万元/疗程。考虑到中国市场的价格敏感度，我们给出的初始报价是9.8万元。根据我们全球定价模型的分析，这个价格已经是将中国的人均GDP、医保支付能力和市场规模全部纳入计算后的结果。",emotion:"confident",options:[{id:"A",type:"pressure",label:"价格质疑",text:"9.8万？你们在印度授权仿制药的价格不到1.5万。中国有8.5万患者急需此药——我们不可能接受近7倍的价格差异。请解释。",nextNode:"r1_pressure_response",effects:{priceChange:-18e3}},{id:"B",type:"empathy",label:"市场逻辑",text:'如果这个药不能进医保，8.5万名中国肿瘤患者中大多数根本用不起。但反过来看——一旦纳入医保，这将是全球最大的肿瘤药单一市场。不是"降价"，是打开一扇大门。',nextNode:"r1_empathy_response",effects:{priceChange:-1e4}},{id:"C",type:"technical",label:"疗效数据",text:"临床数据显示：中国患者用药后的肿瘤缩小率（34%）低于全球平均水平（42%）。既然对中国患者的疗效打了折扣，价格也应该相应调整——我们的测算模型建议不超过5.5万。请回应。",nextNode:"r1_technical_response",effects:{priceChange:-15e3}}]},r1_pressure_response:{nodeId:"r1_pressure_response",speaker:"pharma",speakerName:"全球肿瘤药事业部代表",text:'（面不改色，翻开一页文件）印度的情况完全不同——那是"自愿许可"机制下的例外，仿制药厂不需要承担任何研发费用。中国作为全球第二大创新药市场，价格必须反映研发投入。给你一个数据：从实验室到获批，这个药走了12年，烧了15亿美元。进入临床试验的100个候选分子中，只有不到12个能最终上市。刚才你提到的每一个折扣数字，都是这88个失败项目的成本没有被覆盖到的代价。不过——我们可以在第二轮调整报价。',emotion:"defensive",isEndOfRound:!0},r1_empathy_response:{nodeId:"r1_empathy_response",speaker:"pharma",speakerName:"全球肿瘤药事业部代表",text:"（微微点头）这个市场规模的逻辑是成立的。如果纳入医保确实意味着年销售量达到一定规模——以量换价我们完全可以谈。第二轮我们会基于这个思路调整方案。",emotion:"conciliatory",isEndOfRound:!0},r1_technical_response:{nodeId:"r1_technical_response",speaker:"pharma",speakerName:"全球肿瘤药事业部代表",text:'（快速翻阅临床数据）中国亚组的数据确实显示了一些差异，但这可能跟入组患者的病情阶段分布有关——不能简单归因为"药对中国患者效果差"。不过——（合上报告）我们尊重数据。第二轮会据此调整报价。',emotion:"defensive",isEndOfRound:!0}},round2:{startNode:"r2_start",r2_start:{nodeId:"r2_start",speaker:"pharma",speakerName:"全球肿瘤药事业部代表",text:'（推过来一份新的报价单）经过与总部紧急沟通，我们可以降至7.2万元。这是基于中国市场的"以量换价"逻辑——前提是纳入医保后年采购量不低于5万疗程。低于这个量，这个价格无法维持。这是我们的底线。',emotion:"conciliatory",options:[{id:"A",type:"pressure",label:"专利施压",text:"7.2万还是太高。据我所知，你们下个月在欧洲面临关键专利到期。届时仿制药一旦涌入，中国市场的及时准入对你们全球收入的稳定至关重要——建议贵方重新考虑。",nextNode:"r2_pressure_response",effects:{priceChange:-25e3}},{id:"B",type:"empathy",label:"患者倒计时",text:"以量换价我们认可。但有一个事实请记住——我们每拖延一轮谈判，都有肿瘤患者在这期间因为用不起药而离开这个世界。今天我们能不能坐下来，谈出一个真正让患者用得起、也让你们有合理回报的价格？",nextNode:"r2_empathy_response",effects:{priceChange:-2e4}},{id:"C",type:"technical",label:"全球比价",text:"我们的团队已经拉出了这个药在全球主要市场的实际售价：德国4.8万、日本5.2万、澳大利亚4.5万。再结合中国人均GDP调整因子，4.8万才是对标全球的公平价格。请你们的数据团队也复核一下这个数字。",nextNode:"r2_technical_response",effects:{priceChange:-26e3}}]},r2_pressure_response:{nodeId:"r2_pressure_response",speaker:"pharma",speakerName:"全球肿瘤药事业部代表",text:"（瞳孔微缩，迅速在手边的平板上查了一些东西）……专利信息是公开的，你查得很准。下个月的欧洲专利悬崖确实在我们的风险评估报告里。基于这个新变量，我可以在授权范围内做最后一次调整。这是最终报价。",emotion:"defensive",triggerEnvelope:!0},r2_empathy_response:{nodeId:"r2_empathy_response",speaker:"pharma",speakerName:"全球肿瘤药事业部代表",text:"（沉默了许久，放下手中的笔）我刚才跟你说数字、模型、底线——但你提醒了我，在这些数字背后是活生生的人。是的，我们今天就该给患者一个答案。不是为了交差——是因为每一轮拖延确实都有代价。让我们结束这场谈判。",emotion:"sympathetic",triggerEnvelope:!0},r2_technical_response:{nodeId:"r2_technical_response",speaker:"pharma",speakerName:"全球肿瘤药事业部代表",text:"（戴上眼镜，仔细核对了你递过来的全球比价表整整两分钟）德国4.8、日本5.2、澳大利亚4.5……你们的团队做了功课。基于这些数据和我们内部的价格模型交叉验证——你的数字是站得住脚的。这是我们基于全球市场数据做出的最终报价。",emotion:"confident",triggerEnvelope:!0}}},h={round1:{startNode:"r1_pharma_open",r1_pharma_open:{nodeId:"r1_pharma_open",speaker:"pharma",speakerName:"辉瑞中国代表",text:'（微笑着推过来一份文件）立普妥在医保目录里已经服务中国患者8年了，累计开了超过30亿张处方——全国2亿多高血脂患者，很多人每天的"小蓝片"就是它。我们今天的续约报价是：维持每片5.6元不变。坦率地说，这已经是全球最低价格梯队了，我们再降的空间非常有限。',emotion:"confident",options:[{id:"A",type:"pressure",label:"销量施压",text:"维持原价？原协议预估每年卖5000万盒，你们实际卖了2.1亿盒——是预估的4倍！卖得越多单盒成本越低，价格不该相应地降下来吗？",nextNode:"r1_pressure_response",effects:{priceChange:-1.4}},{id:"B",type:"empathy",label:"患者考量",text:"立普妥确实是好药，2亿患者每天都在用它控制血脂。但正因为用量这么大——每降1分钱，医保基金每年就能多释放几个亿的空间去覆盖更多救命药。这不是为难你们，是让这笔钱发挥最大的社会价值。",nextNode:"r1_empathy_response",effects:{priceChange:-.8}},{id:"C",type:"technical",label:"规则核算",text:"根据最新的续约规则：当实际销量超过预估销量的3倍以上时，必须重新测算降价比例。这个规则对所有药企一视同仁——不是针对立普妥。我们的测算模型建议降至3.2元。请你们核算一下。",nextNode:"r1_technical_response",effects:{priceChange:-1.8}}]},r1_pressure_response:{nodeId:"r1_pressure_response",speaker:"pharma",speakerName:"辉瑞中国代表",text:"（笑容收了一些，但语气仍然平稳）销量超预期恰恰说明这个药真正帮到了中国患者——这不就是医保的初衷吗？如果每次药品卖得好就要被惩罚性地砍价，那我们这些药企还有什么动力去深入基层、让更多偏远地区的患者用上好药？我觉得规则可以执行，但方式上应该有温度。第二轮我们拿一个新方案出来。",emotion:"defensive",isEndOfRound:!0},r1_empathy_response:{nodeId:"r1_empathy_response",speaker:"pharma",speakerName:"辉瑞中国代表",text:"（点了点头）这个视角我认同。医保基金的每一分钱都该花在刀刃上——立普妥用量大，降价确实能给更多人腾出空间。基于公平原则，我们愿意重新核算。第二轮见。",emotion:"conciliatory",isEndOfRound:!0},r1_technical_response:{nodeId:"r1_technical_response",speaker:"pharma",speakerName:"辉瑞中国代表",text:"（仔细看了一遍续约规则条款）3.2元非常接近我们的成本线了。但规则确实写得清楚，我们有义务配合重新测算。给我们再做一轮评估，第二轮带着调整方案回来。",emotion:"defensive",isEndOfRound:!0}},round2:{startNode:"r2_start",r2_start:{nodeId:"r2_start",speaker:"pharma",speakerName:"辉瑞中国代表",text:"（与团队简单交换意见后）经过重新核算，我们愿意降至每片4.8元。但我必须坦诚相告：这已经接近我们的边际成本了。在新的8年协议期内，不能再追加降价——企业需要一个可预期、可规划的定价环境，才敢在中国市场持续投入。这是8年合作换来的信任，我不希望今天把它用光。",emotion:"conciliatory",options:[{id:"A",type:"pressure",label:"对标仿制药",text:"4.8元还是不够。仿制药集采价格已经压到了1.5元一片。你们的定价是仿制药的3倍多——这个差距怎么向公众和审计部门解释？",nextNode:"r2_pressure_response",effects:{priceChange:-1.7}},{id:"B",type:"empathy",label:"珍惜合作",text:"8年来立普妥零质量事故，这份信任是双方一点一点建立起来的。我愿意本着这份信任，让更多中国患者以负担得起的价格继续用上这个好药。希望我们之间的合作能走得更远。",nextNode:"r2_empathy_response",effects:{priceChange:-1.4}},{id:"C",type:"technical",label:"阶梯定价",text:"我们提一个折中方案——阶梯定价：前2亿盒维持4块多，超出2亿盒的部分自动降至3.2元。这样你们的利润核心盘有保障，医保基金也不会被超额销量拖垮。两全其美。",nextNode:"r2_technical_response",effects:{priceChange:-1.5}}]},r2_pressure_response:{nodeId:"r2_pressure_response",speaker:"pharma",speakerName:"辉瑞中国代表",text:'（面色凝重起来）仿制药1.5元是集采中标的极端价格——那种价格下厂家几乎零利润，只靠走量。但原研药有几十年几千万患者用过之后积累的安全性数据，这不是一句"成分一样"就能抹平的差距。不过——（叹了口气）我理解基金的压力。这是我们的最终报价。我们还有12个在研新药——今天的谈判结果，总部会认真审视，来判断中国市场是否值得继续投入大量资源。我希望答案是肯定的。',emotion:"defensive",triggerEnvelope:!0},r2_empathy_response:{nodeId:"r2_empathy_response",speaker:"pharma",speakerName:"辉瑞中国代表",text:"（微笑）8年了，信任无价。立普妥是我们在中国最自豪的产品——不只是销售数字，而是它真正守护了几亿中国人的血管健康。为了延续这份信任，我们愿意为患者再让一步。请听最终报价。",emotion:"conciliatory",triggerEnvelope:!0},r2_technical_response:{nodeId:"r2_technical_response",speaker:"pharma",speakerName:"辉瑞中国代表",text:"（眼睛一亮）阶梯定价——这个思路好。既保证了患者用得起的量，也给了企业一个可以预期的利润底线。三方共赢的方案。基于这个框架，我们调整最终报价。",emotion:"confident",triggerEnvelope:!0}}},C="./";function i(e){return`${C}audio/${e}`}const b={"rare-disease-1":{id:"rare-disease-1",name:"案例二：罕见病救命药",drugInfo:n["rare-disease-1"],rounds:[{roundNumber:1,narrativeIntro:'谈判室的门在你身后关上了。对面是全球排名前三的跨国药企代表。你的桌上放着一份1200名SMA患儿的名单——他们患上了一种叫"脊髓性肌萎缩症"的罕见病，全身会逐渐失去力气，最终连呼吸都变得困难。全球只有6万名患者，因为患病的人太少，药企研发的动力不足，这类药在业内被叫做"孤儿药"——不是药被抛弃了，而是这些孩子被市场"遗忘"了。今天，你要帮他们发出声音。',pharmaOpeningQuote:12e4,floorPrice:55e3,timerSeconds:120,triggerPhoneCall:!1,dialogueTree:u.round1},{roundNumber:2,narrativeIntro:'第一轮硝烟未散，你的手机在桌上震动——是一位SMA患儿的母亲打来的微信电话。按照规则，药企还有最后一次报价机会。如果报价仍然高于医保局内部测算的底价上限（大约是底价的1.15倍，相当于只给你留了15%的"商量余地"），谈判就直接宣告失败。这是双方最后的协商窗口——1200个家庭的希望，都压在这一轮了。',pharmaOpeningQuote:8e4,floorPrice:55e3,timerSeconds:90,triggerPhoneCall:!0,dialogueTree:u.round2}],realResult:{finalPrice:33e3,discount:"降价72%",negotiatorName:"张劲妮",negotiatorQuote:"每一个小群体都不应该被放弃",year:2021},policyTags:["罕见病","保基本","价格谈判"],deepReads:[{title:"2025年国家医保目录调整工作方案",contentId:"adjustment-plan-2025"},{title:"罕见病药物纳入医保的挑战与路径",contentId:"rare-disease-path"}],phoneCall:{callerName:"SMA患儿母亲",callerRelation:"患儿家属",message:"谈判官您好……我的孩子今年3岁了，医生说如果能用上这个药，他就有可能站起来走路。我们知道药很贵，但请无论如何帮帮我们。",audioSrc:i("mother-message.mp3")}},"tumor-drug-2":{id:"tumor-drug-2",name:"案例三：肿瘤靶向药",drugInfo:n["tumor-drug-2"],rounds:[{roundNumber:1,narrativeIntro:'对面是全球肿瘤药巨头，他们的王牌产品——一种叫"免疫 checkpoint 抑制剂"的广谱抗癌药（学术名叫PD-1抑制剂），在欧美定价约15万元一个疗程。但他们也很清楚：中国有8.5万名肿瘤患者在等着这个药。一个新药从实验室到上市平均需要12年、烧掉超过15亿美元——更残酷的是，进入临床试验的100个候选药物里，最后能活着走到药店的不到12个。你既要为8.5万中国患者争一个用得起的公平价格，又不能传递出"中国市场不欢迎创新"的信号——毕竟，未来的新药研发也需要有人愿意冒险投钱。这是一场在"生命"和"商业"之间走钢丝的谈判。',pharmaOpeningQuote:98e3,floorPrice:48e3,timerSeconds:120,triggerPhoneCall:!1,dialogueTree:_.round1},{roundNumber:2,narrativeIntro:'药企代表拿出一沓厚厚的研发成本报告，数字很震撼："这个药用了12年、烧了15亿美元才做出来。"药企希望用这些沉默成本来证明高价的合理性。但你手中有一份利器——多国参考价模型：你的团队已经把这个药在德国、日本、澳大利亚等国的实际售价全部拉出来横向对比过，再根据中国人均收入水平重新计算出了一个"在中国该卖多少钱"的合理数字。中国医保的独特优势是14亿人的市场规模——"以量换价"的底牌就在你手上。现在，用这个逻辑说服对方。',pharmaOpeningQuote:72e3,floorPrice:48e3,timerSeconds:100,triggerPhoneCall:!0,dialogueTree:_.round2}],realResult:{finalPrice:42e3,discount:"降价57%",negotiatorName:"国家医保局谈判组",negotiatorQuote:"以量换价，用14亿人的市场规模换取企业合理降价空间",year:2024},policyTags:["肿瘤药","跨国谈判","定价机制"],deepReads:[{title:"PD-1抑制剂全球定价机制比较",contentId:"pd1-global-pricing"},{title:"药物经济学模型如何影响谈判",contentId:"pharma-economics"}],phoneCall:{callerName:"药物经济学专家组",callerRelation:"场外技术支持",message:"谈判官，我们刚完成了艾瑞卡在全球7个主要市场的定价模型交叉验证。德国4.8万、日本5.2万、澳大利亚4.5万——这是他们自己的全球定价体系。结合中国人均GDP调整，4.8万是站得住脚的底线。注意他们可能会拿印度仿制药说事，但那是自愿许可的特殊情况，不能作为参照。祝你谈判顺利。",audioSrc:i("expert-call.mp3")}},"chronic-renewal-3":{id:"chronic-renewal-3",name:"案例一：慢性病用药续约",drugInfo:n["chronic-renewal-3"],rounds:[{roundNumber:1,narrativeIntro:'这次的对手有些不同。对方不是新面孔，而是在医保目录里服务了8年的老朋友——辉瑞公司的降脂药"立普妥"。中国有2亿高血脂患者，这个药是很多人的日常必备，8年累计开了超过30亿张处方。但问题出在一个谁也没料到的数字上：当初签协议时预估每年卖5000万盒，可实际需求太大，一年卖了2.1亿盒——是预估的4倍！医保基金为此多花了一大笔钱。按照新规：药物销量严重超标后，药企必须在续约时重新谈价格。道理很简单：卖得越多，单盒成本越低——价格就该越低。但也有人说：如果药品卖得好反而要被"罚"，那以后药企还敢在中国推广好药吗？',pharmaOpeningQuote:5.6,floorPrice:3.2,timerSeconds:100,triggerPhoneCall:!1,dialogueTree:h.round1},{roundNumber:2,narrativeIntro:'第一轮没有谈拢。药企坚持目前的定价"已经是全球最低了"，但摆在面前的数据没法回避——按现在的销量增速，明年医保基金的预算将出现严重缺口。这里有一个容易被忽略的细节：立普妥是"原研药"（辉瑞最早研发出来的原版），市面上还有很多过了专利期后其他药厂照着配方做的"仿制药"，价格只有原研药的几分之一。但原研药有几十年来几千万患者使用后积累的安全性数据——这不只是"药效一样不一样"的问题，而是一份沉甸甸的临床信任。你的任务不是简单地"价低者赢"，而是要在这份信任和基金可持续之间，找到一个公平的平衡点。',pharmaOpeningQuote:4.8,floorPrice:3.2,timerSeconds:90,triggerPhoneCall:!0,dialogueTree:h.round2}],realResult:{finalPrice:3,discount:"再降37%（累计降幅82%）",negotiatorName:"国家医保局谈判组",negotiatorQuote:"医保基金每一分钱都要花在刀刃上——量大就该价优",year:2024},policyTags:["续约机制","慢性病","规则博弈"],deepReads:[{title:"药品续约规则详解",contentId:"renewal-rules"},{title:"8年独家品种转常规：新规解读",contentId:"innovation-balance"}],phoneCall:{callerName:"乡镇卫生院医生",callerRelation:"基层医疗机构",message:"谈判官您好，我是湖南一个乡镇卫生院的。我们这里很多老人家血脂高，立普妥是控制得最稳定的药。如果价格能再降一点，我们就能给更多村民开这个药了。拜托您了。",audioSrc:i("doctor-call.mp3")}}};function T(e){return b[e]||null}const S={key:0,class:"modal-overlay__header"},P={class:"modal-overlay__title"},E={class:"modal-overlay__body"},R={key:1,class:"modal-overlay__footer"},O={__name:"ModalOverlay",props:{visible:{type:Boolean,default:!1},title:{type:String,default:""},maxWidth:{type:String,default:"360px"}},emits:["close"],setup(e,{emit:f}){const g=f;function p(){g("close")}return(a,d)=>(r(),y(c,{name:"fade"},{default:l(()=>[e.visible?(r(),o("div",{key:0,class:"modal-overlay",onClick:x(p,["self"])},[N(c,{name:"slide-up"},{default:l(()=>[e.visible?(r(),o("div",{key:0,class:"modal-overlay__content",style:k({maxWidth:e.maxWidth})},[e.title||a.$slots.header?(r(),o("div",S,[t("h3",P,v(e.title),1),t("button",{class:"modal-overlay__close",onClick:p,"aria-label":"关闭"},[...d[0]||(d[0]=[t("svg",{width:"20",height:"20",viewBox:"0 0 20 20",fill:"none"},[t("path",{d:"M15 5L5 15M5 5l10 10",stroke:"currentColor","stroke-width":"1.5","stroke-linecap":"round"})],-1)])])])):s("",!0),t("div",E,[m(a.$slots,"default",{},void 0,!0)]),a.$slots.footer?(r(),o("div",R,[m(a.$slots,"footer",{},void 0,!0)])):s("",!0)],4)):s("",!0)]),_:3})])):s("",!0)]),_:3}))}},w=I(O,[["__scopeId","data-v-587f5b9c"]]);export{w as M,T as a,i as g};
